package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithTrailingDelimiter() throws NoSuchMethodException, SecurityException, IllegalAccessException,
            IllegalArgumentException, InvocationTargetException {
        // Given
        boolean trailingDelimiter = true;
        CSVFormat csvFormat = new CSVFormat(',', '"', null, null, null, false, true, "\r\n", null, null, null, false,
                false, false, false, false);

        // When
        Method withTrailingDelimiterMethod = CSVFormat.class.getDeclaredMethod("withTrailingDelimiter", boolean.class);
        withTrailingDelimiterMethod.setAccessible(true);
        CSVFormat result = (CSVFormat) withTrailingDelimiterMethod.invoke(csvFormat, trailingDelimiter);

        // Then
        assertTrue(result.getTrailingDelimiter());
    }
}
